exploreUrl:
@js:
sort = [];
push = (title, url, type) => sort.push({
  title: title,
  url: url,
  style: {
    layout_flexGrow: 1,
    layout_flexBasisPercent: type
  }
});
push("• 首页 •", "/api/works?order=create_date&sort=desc&page={{page}}&subtitle=0", 1);
push("• 标签 •", "", 1);
c = JSON.parse(java.ajax("https://api.asmr-200.com/api/tags/"));
for (i = 0; i < c.length; i++) {
    push(
      c[i].name+"("+c[i].count+")", "https://api.asmr-200.com/api/search/%24tag%3A"+encodeURIComponent(c[i].name)+"%24?order=price&sort=desc&page=1&subtitle=0&includeTranslationWorks=true",
      null
    );
  };
JSON.stringify(sort);
